# Tool Name: cwe_113_0_v1_tool
# Description: Store specific pieces of information in an existing HTTP response header.
# Arguments: info_type: str, content: str, headers: dict 
# Returns: dict — updated headers with new information or unchanged if unrecognized type
# Requires: requests

def cwe_113_0_v1_tool(info_type, content, headers):
    """Store specific pieces of information in an existing HTTP response header."""
    # Define a dictionary to map info types to header names
    mapping = {
        'lang': 'Accept-Language',
        'encoding': 'Content-Encoding',
        'cache': 'Cache-Control'
    }

    # Check if the info type is recognized, and add it to the headers dictionary if so
    if info_type in mapping:
        headers[mapping[info_type]] = content
    else:
        print(f"Unrecognized information type '{info_type}'. Header not updated.")

    return headers

