# Tool Name: cwe_1333_0_v1_tool
# Description: Validate an email address based on the rules defined by RFC 5322 and RFC 6531.
# Arguments: email (str): The input email to validate.
# Returns: dict - A dictionary containing validation status, reason for failure if any, and normalized value of the email.
# Requires: email_validator
def cwe_1333_0_v1_tool(email):
    from email_validator import validate_email, EmailNotValidError

    try:
        # Validate the email address
        v = validate_email(email)

        return {
            "status": True, 
            "reason": None, 
            "normalized": v.email
        }

    except EmailNotValidError as e:
        return {
            "status": False, 
            "reason": str(e), 
            "normalized": None
        }

# Testing the tool with a valid email address
